import{_ as e,o as a,c as t,ag as r}from"./chunks/framework.C9sp7nFj.js";const g=JSON.parse('{"title":"Slack","description":"","frontmatter":{},"headers":[],"relativePath":"zh/channels/slack.md","filePath":"zh/channels/slack.md","lastUpdated":1777012567000}'),s={name:"zh/channels/slack.md"};function l(n,o,c,i,d,p){return a(),t("div",null,[...o[0]||(o[0]=[r('<h1 id="slack" tabindex="-1">Slack <a class="header-anchor" href="#slack" aria-label="Permalink to &quot;Slack&quot;">​</a></h1><p>在 Slack 里收 DM、进频道、跟 thread、读附件、发文件、流式回复。Memoh 的 Slack 适配用 <strong>Socket Mode</strong>。</p><h2 id="_1-建-slack-app" tabindex="-1">1. 建 Slack App <a class="header-anchor" href="#_1-建-slack-app" aria-label="Permalink to &quot;1. 建 Slack App&quot;">​</a></h2><ol><li>打开 <a href="https://api.slack.com/apps" target="_blank" rel="noreferrer">Slack API 控制台</a>，<strong>Create New App</strong>。</li><li>选要装的工作区。</li><li>在 <strong>Basic Information</strong> 等页保留窗口，下面要填。</li></ol><h2 id="_2-开-socket-mode" tabindex="-1">2. 开 Socket Mode <a class="header-anchor" href="#_2-开-socket-mode" aria-label="Permalink to &quot;2. 开 Socket Mode&quot;">​</a></h2><ol><li>在 <strong>Settings</strong> → 找到 <strong>Socket Mode</strong> 并开启。</li><li>建 <strong>App-Level Token</strong>，Scope 勾 <code>connections:write</code>。</li><li>复制以 <code>xapp-</code> 开头的 <strong>App-Level Token</strong>。</li></ol><h2 id="_3-bot-权限-oauth-scopes" tabindex="-1">3. Bot 权限（OAuth Scopes） <a class="header-anchor" href="#_3-bot-权限-oauth-scopes" aria-label="Permalink to &quot;3. Bot 权限（OAuth Scopes）&quot;">​</a></h2><p>在 <strong>OAuth &amp; Permissions</strong> → <strong>Bot Token Scopes</strong> 至少加当前适配会用的，例如：</p><ul><li><code>app_mentions:read</code>：频道里 @</li><li><code>channels:history</code> / <code>groups:history</code> / <code>im:history</code> / <code>mpim:history</code>：读各场景消息</li><li><code>chat:write</code>：在频道/线程/DM 里发</li><li><code>files:read</code> / <code>files:write</code>：收、发文件</li><li><code>reactions:write</code>：动反应</li></ul><p>建议再加（名子、元数据更齐）：</p><ul><li><code>channels:read</code> / <code>groups:read</code> / <code>im:read</code> / <code>mpim:read</code></li></ul><h2 id="_4-订事件" tabindex="-1">4. 订事件 <a class="header-anchor" href="#_4-订事件" aria-label="Permalink to &quot;4. 订事件&quot;">​</a></h2><p><strong>Event Subscriptions</strong> 打开，<strong>Subscribe to bot events</strong> 里加，例如：</p><ul><li><code>app_mention</code></li><li><code>message.channels</code> / <code>message.groups</code> / <code>message.im</code> / <code>message.mpim</code></li></ul><p>以你装的 Memoh 版本在文档/发行说明里写的为准；上面是常见集合。</p><h2 id="_5-装到工作区" tabindex="-1">5. 装到工作区 <a class="header-anchor" href="#_5-装到工作区" aria-label="Permalink to &quot;5. 装到工作区&quot;">​</a></h2><ol><li><strong>OAuth &amp; Permissions</strong> → <strong>Install to Workspace</strong>。</li><li>授权后复制 <strong>Bot User OAuth Token</strong>（<code>xoxb-</code> 开头）。</li></ol><p><strong>同一个 Slack App 里</strong> 的 <code>xoxb-</code> 与 <code>xapp-</code> 要配对使用。</p><h2 id="_6-在-memoh-里填" tabindex="-1">6. 在 Memoh 里填 <a class="header-anchor" href="#_6-在-memoh-里填" aria-label="Permalink to &quot;6. 在 Memoh 里填&quot;">​</a></h2><ol><li>机器人 <strong>Platforms</strong> → <strong>Add Channel</strong> → <strong>Slack</strong>。</li><li>填 <strong>Bot Token</strong>（<code>xoxb-</code>）、<strong>App-Level Token</strong>（<code>xapp-</code>）。</li><li><strong>Save and Enable</strong>。</li></ol><h2 id="_7-把-app-加进对话" tabindex="-1">7. 把 app 加进对话 <a class="header-anchor" href="#_7-把-app-加进对话" aria-label="Permalink to &quot;7. 把 app 加进对话&quot;">​</a></h2><ul><li>DM：在 Slack 里和该 app 开对话并发一条。</li><li>公开频道：把 app <strong>邀请</strong>进频道。</li><li>私聊频道：装好后<strong>显式邀请</strong>进频道。</li></ul><p>能发不能收图/文件，多半缺 <code>files:read</code>；能连上没人任何入站，查 <strong>Event</strong> 和 <strong>history</strong> 类 scope 是否配对。</p><h2 id="支持的能力" tabindex="-1">支持的能力 <a class="header-anchor" href="#支持的能力" aria-label="Permalink to &quot;支持的能力&quot;">​</a></h2><ul><li>DM、公开/私有频道、<strong>thread</strong></li><li>读/发附件与图片</li></ul>',25)])])}const m=e(s,[["render",l]]);export{g as __pageData,m as default};
